const FP=`<p class="fp"><a href="#">Privacy Statement</a></p>`;

document.querySelectorAll('.tab').forEach(t=>t.addEventListener('click',()=>{
  document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));
  document.querySelectorAll('.panel').forEach(x=>x.classList.remove('active'));
  t.classList.add('active');
  document.getElementById('p'+t.dataset.t).classList.add('active');
}));

function add(id,h){const c=document.getElementById(id),d=document.createElement('div');d.innerHTML=h;while(d.firstChild)c.appendChild(d.firstChild);c.scrollTop=c.scrollHeight}
function bot(t){return`<div class="m mb">${t}${T}</div>`}
function usr(t){return`<div class="m mu">${t}</div>`}

