// === Email capture block (stacked) ===
function emailBlock(label,sub){
  return `<div class="ec">
    <div class="ec-t">${label}</div>
    <div class="ec-sub">${sub}</div>
    <input type="email" placeholder="your.email@company.com">
    <button class="ec-btn" onclick="this.closest('.ec').innerHTML='<div style=\\'padding:12px;text-align:center\\'><div style=\\'color:#3F6FAE;font-weight:600;font-size:13px\\'>&#10003; Summary sent.</div></div>'">Send</button>
    <button class="ec-skip" onclick="this.closest('.ec').innerHTML='<div style=\\'padding:8px;font-size:12px;color:#888\\'>Dismissed.</div>'">Skip</button>
    ${FP}
  </div>`;
}

