function mkStep(p,steps,wHtml){
    let s=0;const n=steps.length;
  const pb=document.getElementById(p+'-p'),nb=document.getElementById(p+'-n'),lb=document.getElementById(p+'-l');
  function u(){lb.textContent=`${s+1} / ${n}`;pb.disabled=s<=0;nb.disabled=s>=n-1}
  function rst(){document.getElementById('c'+p.toUpperCase()).innerHTML=wHtml}
  nb.addEventListener('click',()=>{if(s<n-1){s++;if(steps[s])steps[s]();u()}});
  pb.addEventListener('click',()=>{if(s>0){rst();s--;for(let i=1;i<=s;i++)if(steps[i])steps[i]();u()}});
  window['_jump'+p]=function(from,to){document.getElementById('c'+p.toUpperCase()).innerHTML='';for(let i=from;i<=to;i++){s=i;if(steps[i])steps[i]()}u()};
  u();
}
mkStep('a',sA,WA);mkStep('b',sB,W);mkStep('c',sC,W);mkStep('d',sD,W);
